function calculateEconomicImpact(inputs) {
  const regionPopulation = Math.max(0, inputs.regionPopulation);
  const avgDailyGDPperCapita = Math.max(0, inputs.avgDailyGDPperCapita);
  const stormDurationDays = Math.max(0, inputs.stormDurationDays);
  const pctBusinessesAffected = Math.min(100, Math.max(0, inputs.pctBusinessesAffected)) / 100;
  const infrastructureDamageCost = Math.max(0, inputs.infrastructureDamageCost);
  const emergencyResponseCost = Math.max(0, inputs.emergencyResponseCost);
  const supplyChainDisruptionFactor = Math.max(1.0, inputs.supplyChainDisruptionFactor); // Must be >= 1.0
  const longTermRecoveryFactor = Math.min(100, Math.max(0, inputs.longTermRecoveryFactor)) / 100;
  const insuranceCoverageRate = Math.min(100, Math.max(0, inputs.insuranceCoverageRate)) / 100;
  const avgAnnualWage = Math.max(0.01, inputs.avgAnnualWage); // Avoid division by zero

  // Step 1: Calculate Direct Business Revenue Loss
  const directBusinessRevenueLoss = regionPopulation * avgDailyGDPperCapita * stormDurationDays * pctBusinessesAffected;

  // Step 2: Calculate Direct Infrastructure & Recovery Costs
  const longTermRecoveryCost = infrastructureDamageCost * longTermRecoveryFactor;
  const directInfrastructureDamageTotal = infrastructureDamageCost + emergencyResponseCost + longTermRecoveryCost;

  // Step 3: Calculate Indirect & Supply Chain Impact
  // This factor is applied to the sum of direct business loss and direct infrastructure damage. 
  // The factor is > 1.0, so (factor - 1) gives the additional percentage.
  const baseForIndirect = directBusinessRevenueLoss + infrastructureDamageCost; 
  const indirectSupplyChainImpact = baseForIndirect * (supplyChainDisruptionFactor - 1);

  // Step 4: Calculate Total Estimated Economic Cost
  const totalEconomicCost = directBusinessRevenueLoss + directInfrastructureDamageTotal + indirectSupplyChainImpact;

  // Step 5: Calculate Net Cost to Region (Uninsured Portion)
  // Only direct business and initial infrastructure damage usually covered by insurance.
  const totalDirectLossesForInsurance = directBusinessRevenueLoss + infrastructureDamageCost;
  const insuredPortion = totalDirectLossesForInsurance * insuranceCoverageRate;
  const netUninsuredCost = totalEconomicCost - insuredPortion;

  // Step 6: Estimate Equivalent Job-Years Lost
  // Assuming a full year's wage represents the economic value of one job-year.
  const equivalentJobLossYears = totalEconomicCost / avgAnnualWage;

  return {
    totalEconomicCost: totalEconomicCost,
    directBusinessRevenueLoss: directBusinessRevenueLoss,
    directInfrastructureDamageTotal: directInfrastructureDamageTotal,
    indirectSupplyChainImpact: indirectSupplyChainImpact,
    netUninsuredCost: netUninsuredCost,
    equivalentJobLossYears: equivalentJobLossYears
  };
}
